def is_prime(n):
    sqrta = int(sqrt(n))
    for i in range(2, sqrta + 1):
        if n % i == 0:
            return 0;
    return 1;


def prime_factors(n):
    while n % 2 == 0:
        return [2] + prime_factors(n // 2)
    sqrta = int(sqrt(n))

    for i in range(3, sqrta + 1, 2):
        if n % i == 0:
            return [i] + prime_factors(n // i)

    return [n]


